mapper.update:
update polyp_detect_task
task_no = #{taskNo}, patient_id = #{patientId}, source_file_id = #{sourceFileId}, model_id = #{modelId}, status = #{status}, conf_threshold = #{confThreshold}, result_id = #{resultId}, inference_ms = #{inferenceMs}, error_msg = #{errorMsg}, start_time = #{startTime}, finish_time = #{finishTime}, update_by = #{updateBy}, update_time = #{updateTime}, remark = #{remark},
where task_id = #{taskId}

mapper.select:
select task_id, task_no, patient_id, source_file_id, model_id, status, conf_threshold, result_id, inference_ms, error_msg,
       start_time, finish_time, create_by, create_time, update_by, update_time, remark
from polyp_detect_task

    and task_no like concat('%', #{taskNo}, '%')
    and patient_id = #{patientId}
    and model_id = #{modelId}
    and status = #{status}

order by task_id desc
